$a->strings['✅ What RealMember can do'] = '✅ What RealMember can do';
$a->strings['<strong>Risk assessment of all users:</strong> Every registered account is automatically analyzed based on multiple criteria and receives a risk score from 0% to 100%.'] = '<strong>Risk assessment of all users:</strong> Every registered account is automatically analyzed based on multiple criteria and receives a risk score from 0% to 100%.';
$a->strings['<strong>Disposable email detection:</strong> Email addresses are checked against a community-maintained list of thousands of known disposable providers.'] = '<strong>Disposable email detection:</strong> Email addresses are checked against a community-maintained list of thousands of known disposable providers.';
$a->strings['<strong>Detect suspicious domains:</strong> Domain extensions (TLDs) commonly abused for spam are automatically detected.'] = '<strong>Detect suspicious domains:</strong> Domain extensions (TLDs) commonly abused for spam are automatically detected.';
$a->strings['<strong>Keyword scan:</strong> Usernames and registration notes are searched for almost 200 suspicious terms from the fields of pharma, crypto, erotics, and marketing.'] = '<strong>Keyword scan:</strong> Usernames and registration notes are searched for almost 200 suspicious terms from the fields of pharma, crypto, erotics, and marketing.';
$a->strings['<strong>Bot detection (entropy):</strong> Randomly generated nicknames and email prefixes without natural word structure are detected using pattern analysis.'] = '<strong>Bot detection (entropy):</strong> Randomly generated nicknames and email prefixes without natural word structure are detected using pattern analysis.';
$a->strings['<strong>Include admin rules:</strong> Your own email blocklists from Friendica settings are automatically included in the assessment.'] = '<strong>Include admin rules:</strong> Your own email blocklists from Friendica settings are automatically included in the assessment.';
$a->strings['<strong>Filtering & Sorting:</strong> You can filter and sort results by time period, suspected spam, name, email, or risk score.'] = '<strong>Filtering & Sorting:</strong> You can filter and sort results by time period, suspected spam, name, email, or risk score.';
$a->strings['<strong>Search:</strong> A full-text search across names, handles, and email addresses is integrated.'] = '<strong>Search:</strong> A full-text search across names, handles, and email addresses is integrated.';
$a->strings['<strong>Automatic updates:</strong> The disposable domain list can be automatically updated daily via a cron job.'] = '<strong>Automatic updates:</strong> The disposable domain list can be automatically updated daily via a cron job.';
$a->strings['<strong>Seamless integration:</strong> RealMember appears as a tab in Friendica moderation and blends seamlessly into the existing interface.'] = '<strong>Seamless integration:</strong> RealMember appears as a tab in Friendica moderation and blends seamlessly into the existing interface.';
$a->strings['🔒 Security Guarantee'] = '🔒 Security Guarantee';
$a->strings['<strong>Read-only:</strong> RealMember exclusively reads data. No database entries are created, modified, or deleted.'] = '<strong>Read-only:</strong> RealMember exclusively reads data. No database entries are created, modified, or deleted.';
$a->strings['<strong>No automated actions:</strong> RealMember never blocks, deletes, or modifies any account automatically. All decisions are made by the admin.'] = '<strong>No automated actions:</strong> RealMember never blocks, deletes, or modifies any account automatically. All decisions are made by the admin.';
$a->strings['<strong>Only for admins:</strong> The dashboard is only visible to site administrators.'] = '<strong>Only for admins:</strong> The dashboard is only visible to site administrators.';
$a->strings['⚠️ What RealMember cannot do'] = '⚠️ What RealMember cannot do';
$a->strings['<strong>No guarantee:</strong> RealMember is an assistance system. Not every flagged account is actually spam, and not every spammer will be detected.'] = '<strong>No guarantee:</strong> RealMember is an assistance system. Not every flagged account is actually spam, and not every spammer will be detected.';
$a->strings['<strong>No content scan:</strong> Published posts, comments, or messages of users are not analyzed.'] = '<strong>No content scan:</strong> Published posts, comments, or messages of users are not analyzed.';
$a->strings['<strong>No real-time monitoring:</strong> The analysis runs on every page load. There are no push notifications for new suspected spam cases.'] = '<strong>No real-time monitoring:</strong> The analysis runs on every page load. There are no push notifications for new suspected spam cases.';
$a->strings['<strong>No deletion or blocking:</strong> RealMember cannot block or delete accounts. Use Friendica\'s moderation area for this.'] = '<strong>No deletion or blocking:</strong> RealMember cannot block or delete accounts. Use Friendica\'s moderation area for this.';
